import{c as t,Q as o,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"HavenBot ‚Äî onboarding","description":"From passkey to first encrypted buy.","frontmatter":{"title":"HavenBot ‚Äî onboarding","description":"From passkey to first encrypted buy."},"headers":[],"relativePath":"havenbot/onboarding.md","filePath":"havenbot/onboarding.md","lastUpdated":1778986743000}'),n={name:"havenbot/onboarding.md"};function s(i,e,l,d,u,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="onboarding" tabindex="-1">Onboarding <a class="header-anchor" href="#onboarding" aria-label="Permalink to &quot;Onboarding&quot;">‚Äã</a></h1><p>HavenBot&#39;s onboarding wizard takes a first-time investor from &quot;I just heard of MuHaven&quot; to &quot;I hold an encrypted RWA balance and have an audit row to prove it.&quot; The flow follows a Wealthfront-style limits paragraph plus the &quot;sealed-glass-envelope&quot; framing surfaced during user research.</p><h2 id="the-four-steps" tabindex="-1">The four steps <a class="header-anchor" href="#the-four-steps" aria-label="Permalink to &quot;The four steps&quot;">‚Äã</a></h2><p>The wizard at <code>/agent/onboarding</code> is gated by a <code>muhaven:onboarding:complete</code> localStorage flag plus a backend portfolio probe. If you&#39;ve completed it before ‚Äî or if your MuHaven wallet already holds positions ‚Äî you skip straight to the celebrate screen.</p><h3 id="step-1-‚Äî-welcome" tabindex="-1">Step 1 ‚Äî Welcome <a class="header-anchor" href="#step-1-‚Äî-welcome" aria-label="Permalink to &quot;Step 1 ‚Äî Welcome&quot;">‚Äã</a></h3><p>A short explainer that names the three properties that make MuHaven different:</p><ul><li><strong>Encrypted balances.</strong> &quot;Your token balances live on-chain like a sealed glass envelope. The chain can verify the envelope is real and the amount is non-negative ‚Äî but only you can open it.&quot;</li><li><strong>Tiered autonomy.</strong> &quot;You pick how much the agent does without asking. Today: ask me every time.&quot;</li><li><strong>No seed phrase.</strong> &quot;We don&#39;t ever ask you to write down 12 words. Your passkey is the key.&quot;</li></ul><p>Click <strong>Get started</strong> to advance.</p><h3 id="step-2-‚Äî-funding" tabindex="-1">Step 2 ‚Äî Funding <a class="header-anchor" href="#step-2-‚Äî-funding" aria-label="Permalink to &quot;Step 2 ‚Äî Funding&quot;">‚Äã</a></h3><p>You need a small amount of confidential USDC (called <strong>mhUSDC</strong>) to buy your first RWA token.</p><p><strong>Testnet (Arbitrum Sepolia):</strong></p><ul><li>Click <strong>Open faucet</strong> ‚Äî a new tab opens to the public mhUSDC testnet faucet.</li><li>Paste your wallet address (the wizard shows it; click to copy).</li><li>Request the daily drip. (Some faucets dispense less than the full ~100 mhUSDC on first try; rerun if you need more.)</li><li>Come back to the wizard tab and click <strong>I&#39;ve funded my wallet</strong>.</li></ul><p><strong>Production (Arbitrum One):</strong></p><ul><li>Click <strong>Buy mhUSDC</strong> ‚Äî opens the on-ramp picker.</li><li>Pay with card / Apple Pay / Google Pay.</li><li>Wait for on-ramp settlement.</li></ul><p>The wizard polls your mhUSDC balance and advances automatically once funds land.</p><div class="warning custom-block"><p class="custom-block-title">Wrap-to-mhUSDC leaks</p><p>The wrap from USDC ‚Üí mhUSDC is the one MuHaven flow that leaks deposit size to a chain observer. If your deposit size needs to stay private, use the issuer-minted hosted checkout flow (which routes through a non-customer MuHaven wallet).</p></div><h3 id="step-3-‚Äî-first-buy" tabindex="-1">Step 3 ‚Äî First buy <a class="header-anchor" href="#step-3-‚Äî-first-buy" aria-label="Permalink to &quot;Step 3 ‚Äî First buy&quot;">‚Äã</a></h3><p>The wizard shows a tile per active RWA token in the current catalog. Each tile names the asset class (short-duration treasuries, gold, growth basket, shipping receivables, etc.) and links to issuer detail.</p><p>Pick one, enter an amount (default 50 mhUSDC), and click <strong>Continue</strong>. The wizard hands off to ConfirmModal:</p><ol><li>Cleartext preview: amount, estimated shares, current NAV, slippage.</li><li><strong>Confirm</strong> ‚Äî your MuHaven wallet signs the UserOp with the session key.</li><li>Toast: &quot;Signed ‚Üí Bundler ‚Üí Settling‚Ä¶&quot;</li><li>Toast: &quot;Settled. View on Arbiscan.&quot;</li></ol><p>You now hold an encrypted balance of your first RWA token. The ConfirmModal closes; the wizard advances to step 4.</p><h3 id="step-4-‚Äî-celebrate-next-steps" tabindex="-1">Step 4 ‚Äî Celebrate + next steps <a class="header-anchor" href="#step-4-‚Äî-celebrate-next-steps" aria-label="Permalink to &quot;Step 4 ‚Äî Celebrate + next steps&quot;">‚Äã</a></h3><p>A success screen with three calls to action:</p><ul><li><strong>Set your tier.</strong> Default is Advisory (every action prompts your passkey). Most users graduate to Confirm-per-action within their first session.</li><li><strong>Link Telegram.</strong> Open <code>/settings ‚Üí Telegram</code> to bind your MuHaven wallet to a Telegram chat for phone-first access.</li><li><strong>Install MCP.</strong> Open <code>/settings ‚Üí MCP</code> for the device-code authorization flow that lets Claude Code / Desktop / Cursor talk to MuHaven.</li></ul><p>Click <strong>Done</strong>. The wizard sets <code>muhaven:onboarding:complete=true</code> in localStorage. Future visits go straight to <code>/agent</code>.</p><h2 id="what-if-i-close-the-wizard-partway" tabindex="-1">What if I close the wizard partway? <a class="header-anchor" href="#what-if-i-close-the-wizard-partway" aria-label="Permalink to &quot;What if I close the wizard partway?&quot;">‚Äã</a></h2><p>The wizard restores state from a backend portfolio probe plus localStorage:</p><table tabindex="0"><thead><tr><th>You did</th><th>Next visit lands on</th></tr></thead><tbody><tr><td>Nothing</td><td>Step 1 (welcome)</td></tr><tr><td>Funded but didn&#39;t buy</td><td>Step 3 (first buy)</td></tr><tr><td>Bought but didn&#39;t ack the celebrate</td><td>Step 4 (celebrate)</td></tr><tr><td>Acknowledged celebrate</td><td><code>/agent</code> proper (no wizard)</td></tr></tbody></table><p>You can always re-open the wizard from <code>/agent ‚Üí ‚ãØ menu ‚Üí Run onboarding again</code>.</p><h2 id="issuer-onboarding" tabindex="-1">Issuer onboarding <a class="header-anchor" href="#issuer-onboarding" aria-label="Permalink to &quot;Issuer onboarding&quot;">‚Äã</a></h2><p>The investor onboarding wizard runs only for investor-roled MuHaven wallets. Issuers go through a different flow at <code>/apply-issuer</code> for KYB onboarding, and then use HavenBot&#39;s issuer-side tools (distribute yield, KYC churn, unpause new tokens) from the regular <code>/agent</code> route.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">‚Äã</a></h2><ul><li><strong>Funding step won&#39;t advance</strong> ‚Äî the wizard polls your mhUSDC balance every 5 seconds. If the faucet succeeded but the poll hasn&#39;t picked it up, click <strong>I&#39;ve funded my wallet</strong> manually.</li><li><strong>First buy fails with <code>BalanceTooLow</code></strong> ‚Äî your mhUSDC balance is below the amount. Faucet doesn&#39;t always dispense the full 100 mhUSDC on first try; refresh and retry.</li><li><strong>ConfirmModal shows <code>decryptForView</code> errors</strong> ‚Äî your permit may have expired. Refresh the page; HavenBot re-mints the permit on next action.</li><li><strong>Wizard re-opens on every visit</strong> ‚Äî localStorage may be disabled in your browser settings. Whitelist <code>muhaven.app</code> or use a different browser.</li></ul><p>See <a href="/havenbot/troubleshooting">HavenBot troubleshooting</a> for more.</p>',34)])])}const g=t(n,[["render",s]]);export{p as __pageData,g as default};
